import sys

scores = [int(x) for x in sys.argv[1].strip().split('\n')]
buckets = {'A': 0, 'B': 0, 'C': 0, 'D': 0, 'F': 0}
for s in scores:
    if s >= 90:
        buckets['A'] += 1
    elif s >= 80:
        buckets['B'] += 1
    elif s >= 70:
        buckets['C'] += 1
    elif s >= 60:
        buckets['D'] += 1
    else:
        buckets['F'] += 1
for k in ['A', 'B', 'C', 'D', 'F']:
    if buckets[k] > 0:
        sys.stdout.write(f'{k}: {buckets[k]}\n')

import sys
import ast

source = sys.argv[1]
tree = ast.parse(source)
modules = set()
for node in ast.walk(tree):
    if isinstance(node, ast.Import):
        for alias in node.names:
            modules.add(alias.name.split('.')[0])
    elif isinstance(node, ast.ImportFrom):
        if node.module:
            modules.add(node.module.split('.')[0])
sys.stdout.write('\n'.join(sorted(modules)) + '\n')

import sys

data = sys.argv[1]
blocks = data.strip().split('\n\n')

id_to_name = {}
for line in blocks[0].strip().split('\n')[1:]:
    parts = line.split(',')
    id_to_name[parts[0]] = parts[1]

id_scores = []
for line in blocks[1].strip().split('\n')[1:]:
    parts = line.split(',')
    id_scores.append((parts[0], parts[1]))

results = []
for id_, score in id_scores:
    if id_ in id_to_name:
        results.append((id_to_name[id_], score))

results.sort(key=lambda x: x[0])

for name, score in results:
    sys.stdout.write(f'{name} {score}\n')
